class TimeService : Service() {
    inner class TimeBinder : Binder() {
        fun getService(): TimeService = this@TimeService
    }

    private val binder = TimeBinder()

    override fun onBind(intent: Intent): IBinder = binder

    fun getServerTime(): Long = System.currentTimeMillis()
}

class MainActivity : AppCompatActivity() {
    private var timeService: TimeService? = null
    private var bound = false

    private val connection = object : ServiceConnection {
        override fun onServiceConnected(name: ComponentName, binder: IBinder) {
            val localBinder = binder as TimeService.TimeBinder
            timeService = localBinder.getService()
            bound = true
        }
        override fun onServiceDisconnected(name: ComponentName) {
            bound = false
        }
    }

    override fun onStart() {
        super.onStart()
        bindService(Intent(this, TimeService::class.java), connection, BIND_AUTO_CREATE)
    }

    override fun onStop() {
        super.onStop()
        if (bound) { unbindService(connection); bound = false }
    }
}

